import{_ as e,a,b as o}from"./chunks/配置渠道内容.HzNkdrom.js";import{_ as n,o as s,c as d,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Přidání kanálu GitLab Packages","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/upload/gitlab-packages.md","filePath":"cs-CZ/upload/gitlab-packages.md","lastUpdated":1781962217000}'),r={name:"cs-CZ/upload/gitlab-packages.md"};function i(p,t,c,k,u,h){return s(),d("div",null,[...t[0]||(t[0]=[l('<h1 id="pridani-kanalu-gitlab-packages" tabindex="-1">Přidání kanálu GitLab Packages <a class="header-anchor" href="#pridani-kanalu-gitlab-packages" aria-label="Permalink to &quot;Přidání kanálu GitLab Packages&quot;">​</a></h1><h2 id="co-potrebujete-pred-zacatkem" tabindex="-1">Co potřebujete před začátkem <a class="header-anchor" href="#co-potrebujete-pred-zacatkem" aria-label="Permalink to &quot;Co potřebujete před začátkem&quot;">​</a></h2><p>Potřebujete jen tři věci:</p><table tabindex="0"><thead><tr><th>Požadavek</th><th>Účel</th></tr></thead><tbody><tr><td>Účet GitLab</td><td>Pro vytvoření access tokenu a vlastnictví projektu.</td></tr><tr><td>GitLab Personal Access Token</td><td>Umožní ImgBed používat GitLab API, vytvářet projekty a nahrávat soubory do Generic Packages.</td></tr><tr><td>Název projektu</td><td>Můžete zadat jen název projektu, například <code>imgbed</code>.</td></tr></tbody></table><h2 id="nastaveni" tabindex="-1">Nastavení <a class="header-anchor" href="#nastaveni" aria-label="Permalink to &quot;Nastavení&quot;">​</a></h2><h3 id="krok-1-prihlaste-se-do-gitlab-a-vytvorte-access-token" tabindex="-1">Krok 1: Přihlaste se do GitLab a vytvořte Access Token <a class="header-anchor" href="#krok-1-prihlaste-se-do-gitlab-a-vytvorte-access-token" aria-label="Permalink to &quot;Krok 1: Přihlaste se do GitLab a vytvořte Access Token&quot;">​</a></h3><ol><li>Přihlaste se do GitLab.</li><li>Klikněte vpravo nahoře na avatar a otevřete <code>Preferences</code>.</li><li>V levém panelu otevřete <code>Access Tokens</code>.</li><li>Dejte tokenu srozumitelný název.</li><li>Zvolte expiraci podle vlastních potřeb údržby.</li><li>Vyberte scope <code>api</code>.</li><li>Token ihned po vytvoření zkopírujte a uložte.</li></ol><p><img src="'+e+'" alt="Vytvoření legacy tokenu" loading="lazy"></p><p><img src="'+a+'" alt="Výběr oprávnění tokenu" loading="lazy"></p><h2 id="krok-2-vyplnte-kanal-gitlab-packages-v-imgbed" tabindex="-1">Krok 2: Vyplňte kanál GitLab Packages v ImgBed <a class="header-anchor" href="#krok-2-vyplnte-kanal-gitlab-packages-v-imgbed" aria-label="Permalink to &quot;Krok 2: Vyplňte kanál GitLab Packages v ImgBed&quot;">​</a></h2><p>Po výběru <code>GitLab Packages</code> v Nastavení nahrávání vyplňte:</p><table tabindex="0"><thead><tr><th>Pole UI</th><th>Co zadat</th></tr></thead><tbody><tr><td>Název kanálu</td><td>Název podle vás, například <code>GitLabPrimary</code>.</td></tr><tr><td>Access Token</td><td>GitLab Personal Access Token, který jste právě vytvořili.</td></tr><tr><td>Název projektu</td><td>Krátký název jako <code>imgbed</code>, nebo plná cesta jako <code>username/imgbed</code>.</td></tr><tr><td>Soukromý repozitář</td><td>Zapněte nebo vypněte podle potřeby.</td></tr><tr><td>Poznámka</td><td>Volitelné, například <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+o+`" alt="Konfigurace kanálu" loading="lazy"></p><h2 id="krok-3-ulozte-kanal" tabindex="-1">Krok 3: Uložte kanál <a class="header-anchor" href="#krok-3-ulozte-kanal" aria-label="Permalink to &quot;Krok 3: Uložte kanál&quot;">​</a></h2><p>Po vyplnění polí klikněte na Uložit.</p><p>Systém zařídí tyto detaily:</p><table tabindex="0"><thead><tr><th>Chování systému</th><th>Popis</th></tr></thead><tbody><tr><td>Krátký název projektu</td><td>ImgBed rozpozná aktuální účet GitLab a rozšíří hodnotu na plnou cestu projektu.</td></tr><tr><td>Plná cesta projektu</td><td>ImgBed použije <code>username/project</code> přesně tak, jak bylo zadáno.</td></tr><tr><td>Kontrola projektu</td><td>Pokud použijete cestu aktuálního osobního účtu, ImgBed projekt automaticky vytvoří, pokud neexistuje. Pokud zadáte plnou cestu ručně, použije ji přímo.</td></tr><tr><td>Veřejný/soukromý stav</td><td>Viditelnost projektu se synchronizuje podle aktuálního přepínače.</td></tr></tbody></table><h2 id="rychly-checklist" tabindex="-1">Rychlý checklist <a class="header-anchor" href="#rychly-checklist" aria-label="Permalink to &quot;Rychlý checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Přihlaste se do GitLab</span></span>
<span class="line"><span>-&gt; Vytvořte Access Token</span></span>
<span class="line"><span>-&gt; Vyberte jen scope api</span></span>
<span class="line"><span>-&gt; Vraťte se do ImgBed a zadejte token i název projektu</span></span>
<span class="line"><span>-&gt; Uložte</span></span>
<span class="line"><span>-&gt; Pokud je zadán jen název projektu, ImgBed automaticky přidá aktuální uživatelské jméno</span></span>
<span class="line"><span>-&gt; Pokud je zadáno username/project, ImgBed ho použije beze změny</span></span>
<span class="line"><span>-&gt; Nahrajte testovací obrázek</span></span></code></pre></div>`,19)])])}const g=n(r,[["render",i]]);export{m as __pageData,g as default};
